import React, { useState } from 'react';
import ExpenseService from '../services/ExpenseService';

const AddExpense = ({ onExpenseAdded }) => {
    const initialState = {
        projectName: '',
        expenseType: '',
        amount: '',
        vendor: '',
        date: '',
        description: ''
    };

    const [expense, setExpense] = useState(initialState);
    const [message, setMessage] = useState({ text: '', type: '' });
    const [loading, setLoading] = useState(false);

    const expenseTypes = [
        'Materials', 'Labor', 'Equipment', 'Transport',
        'Utilities', 'Subcontractor', 'Permits', 'Miscellaneous'
    ];

    const handleChange = (e) => {
        const { name, value } = e.target;
        setExpense(prev => ({ ...prev, [name]: value }));
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setMessage({ text: '', type: '' });

        try {
            await ExpenseService.createExpense(expense);
            setMessage({ text: '✅ Expense added successfully!', type: 'success' });
            setExpense(initialState);
            if (onExpenseAdded) onExpenseAdded();
        } catch (error) {
            setMessage({ text: '❌ Failed to add expense. Please try again.', type: 'error' });
            console.error('Error adding expense:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleReset = () => {
        setExpense(initialState);
        setMessage({ text: '', type: '' });
    };

    return (
        <div className="add-expense">
            <h2 className="page-title">➕ Add New Expense</h2>

            {message.text && (
                <div className={`alert alert-${message.type}`}>
                    {message.text}
                </div>
            )}

            <div className="form-card">
                <div onSubmit={handleSubmit}>
                    <div className="form-grid">
                        <div className="form-group">
                            <label>Project Name <span className="required">*</span></label>
                            <input
                                type="text"
                                name="projectName"
                                value={expense.projectName}
                                onChange={handleChange}
                                placeholder="e.g. Building Block A"
                                required
                            />
                        </div>

                        <div className="form-group">
                            <label>Expense Type <span className="required">*</span></label>
                            <select
                                name="expenseType"
                                value={expense.expenseType}
                                onChange={handleChange}
                                required
                            >
                                <option value="">-- Select Type --</option>
                                {expenseTypes.map(type => (
                                    <option key={type} value={type}>{type}</option>
                                ))}
                            </select>
                        </div>

                        <div className="form-group">
                            <label>Amount (₹) <span className="required">*</span></label>
                            <input
                                type="number"
                                name="amount"
                                value={expense.amount}
                                onChange={handleChange}
                                placeholder="0.00"
                                min="0"
                                step="0.01"
                                required
                            />
                        </div>

                        <div className="form-group">
                            <label>Vendor / Supplier <span className="required">*</span></label>
                            <input
                                type="text"
                                name="vendor"
                                value={expense.vendor}
                                onChange={handleChange}
                                placeholder="e.g. ABC Constructions"
                                required
                            />
                        </div>

                        <div className="form-group">
                            <label>Date <span className="required">*</span></label>
                            <input
                                type="date"
                                name="date"
                                value={expense.date}
                                onChange={handleChange}
                                required
                            />
                        </div>

                        <div className="form-group full-span">
                            <label>Description</label>
                            <textarea
                                name="description"
                                value={expense.description}
                                onChange={handleChange}
                                placeholder="Optional: Add more details about this expense..."
                                rows="3"
                            />
                        </div>
                    </div>

                    <div className="form-actions">
                        <button
                            type="button"
                            className="btn btn-secondary"
                            onClick={handleReset}
                        >
                            🔄 Reset
                        </button>
                        <button
                            type="button"
                            className="btn btn-primary"
                            onClick={handleSubmit}
                            disabled={loading}
                        >
                            {loading ? 'Saving...' : '💾 Save Expense'}
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default AddExpense;
